js_content = """$(document).ready(function() {
    var listItems = [
        { text: 'Google', link: 'https://google.com', tooltip: 'Search Engine' },
        { text: 'GitHub', link: 'https://github.com', tooltip: 'Code Hosting' },
        { text: 'MDN', link: 'https://developer.mozilla.org', tooltip: 'Web Docs' },
        { text: 'StackOverflow', link: 'https://stackoverflow.com', tooltip: 'Q&A' },
        { text: 'W3Schools', link: 'https://w3schools.com', tooltip: 'Tutorials' }
    ];
    var editIndex = -1;

    function sanitize(str) {
        var div = document('div');
        div.textContent = str;
        return div.innerHTML;
    }

    function renderList() {
        var $list = $('#dynamicList');
        $list.empty();
        listItems.forEach(function(item, index) {
            var li = $("<li>", {
                'class': 'list-group-item list-item-container',
                'html': `<a href='${item.link}' target='_blank' class='tooltip-text' data-toggle='tooltip' title='${item.tooltip}'>${item.text}</a>
                         <div>
                            <button class='btn btn-xs btn-info edit-btn' data-index='${index}'>Edit</button>
                            <button class='btn btn-xs btn-danger del-btn' data-index='${index}'>Remove</button>
                         </div>`
            });
            $list.append(li);
        });
        $('[data-toggle="tooltip"]').tooltip();
    }

    $('#listForm').submit(function(e) {
        e.preventDefault();
        try {
            var text = $('#text').val().trim();
            var link = $('#link').val().trim();
            var tooltip = $('#tooltip').val().trim();

            if (!text || !link || !tooltip) throw new Error('All fields are required.');
            if (!link.startsWith('http')) throw new Error('Link must start with http/https.');

            if (editIndex > -1) {
                listItems[editIndex] = { text: sanitize(text), link: sanitize(link), tooltip: sanitize(tooltip) };
                editIndex = -1;
                $('#updateBtn').hide();
                $('#submitBtn').show();
            } else {
                listItems.push({ text: sanitize(text), link: sanitize(link), tooltip: sanitize(tooltip) });
            }

            $('#listForm')[0].reset();
            $('#errorMessage').hide();
            renderList();
        } catch (err) {
            $('#errorMessage').text(err.message).show();
        }
    });

    $(document).on('click', '.del-btn', function() {
        var idx = $(this).data('index');
        listItems.splice(idx, 1);
        renderList();
    });

    $(document).on('click', '.edit-btn', function() {
        var idx = $(this).data('index');
        var item = listItems[idx];
        $('#text').val(item.text);
        $('#link').val(item.link);
        $('#tooltip').val(item.tooltip);
        editIndex = idx;
        $('#submitBtn').hide();
        $('#updateBtn').show();
    });

    $('#updateBtn').click(function() {
        $('#listForm').submit();
    });

    renderList();
});"""
