    def __init__(self, title, composer, period):
        self.title = title
        self.composer = composer
        self.period = period

class MusicDatabase:
    def __init__(self):
        self.compositions = []

    def add_composition(self, title, composer, period):
        new_composition = Composition(title, composer, period)
        self.compositions.append(new_composition)

    def list_compositions(self):
        return [f'Title: {c.title}, Composer: {c.composer}, Period: {c.period}' for c in self.compositions]

    def search_composition(self, title):
        for composition in self.compositions:
            if composition.title == title:
                return f'Title: {composition.title}, Composer: {composition.composer}, Period: {composition.period}'
        return 'Composition not found'
