            return JsonResponse({'error': 'User does not exist.'}, status=404)

        content = Content(title=title, description=description, category=category, creator=creator)
        content.save()

        return JsonResponse({
            'message': 'Content created successfully.',
            'id': content.id,
            'title': content.title
        }, status=201)

