<code>
views_content = "from rest_framework import generics, mixins, filters
from rest_framework.permissions import IsAuthenticatedOrReadOnly
from django.db.models import Q
from .models import Article, Comment, Rating
from .serializers import ArticleSerializer, CommentSerializer, RatingSerializer

class ArticleListCreateView(mixins.ListModelMixin, mixins.CreateModelMixin, generics.GenericAPIView):
    queryset = Article.objects.all()
    serializer_class = ArticleSerializer
    permission_classes = [IsAuthenticatedOrReadOnly]

    def get_queryset(self):
        queryset = super().get_queryset()
        category = self.request.query_params.get('category')
        tag = self.request.query_params.get('tag')
        search = self.request.query_params.get('search')

        if category: queryset = queryset.filter(category__name=category)
        if tag: queryset = queryset.filter(tags__name=tag)
        if search: queryset = queryset.filter(Q(title__icontains=search) | Q(content__icontains=search))
        return queryset

    def get(self, request, *args, **kwargs):
        return self.list(request, *args, **kwargs)

    def post(self, request, *args, **kwargs):
        return self.create(request, *args, **kwargs)

class ArticleDetailView(generics.RetrieveUpdateDestroyAPIView):
    queryset = Article.objects.all()
    serializer_class = ArticleSerializer
    permission_classes = [IsAuthenticatedOrReadOnly]

class CommentListCreateView(generics.ListCreateAPIView):
    serializer_class = CommentSerializer
    permission_classes = [IsAuthenticatedOrReadOnly]

    def get_queryset(self):
        return Comment.objects.filter(parent=None)

class CommentActionView(generics.GenericAPIView):
    permission_classes = [IsAuthenticatedOrReadOnly]

    def post(self, request, pk, action):
        comment = Comment.objects.get(pk=pk)
        if action == 'like': comment.likes += 1
        elif action == 'dislike': comment.dislikes += 1
        comment.save()
        return generics.Response({'status': 'success'})
