<html>
<head>
    <title>Text Analyzer</title>
    <style>
        body { font-family: sans-serif; margin: 40px; }
        .container { max-width: 600px; }
        textarea { width: 100%; height: 150px; }
        .results { margin-top: 20px; padding: 10px; border: 1px solid #ccc; }
        .error { color: red; }
        table { border-collapse: collapse; width: 100%; }
        td, th { border: 1px solid #ddd; padding: 8px; }
    </style>
</head>
<body>
    <div class='container'>
        <h1>Text Analyzer</h1>
        <textarea id='inputText' placeholder='Enter text here...'></textarea><br><br>
        <button onclick='analyze(false)'>Analyze Text</button>
        <button onclick='analyze(true)'>Filter Stop Words</button>

        <div id='errorArea' class='error'></div>
        <div class='results'>
            <p>Characters: <span id='charCount'>0</span></p>
            <p>Words: <span id='wordCount'>0</span></p>
            <table id='freqTable'>
                <thead><tr><th>Word</th><th>Freq</th></tr></thead>
                <tbody></tbody>
            </table>
        </div>
    </div>

    <script>
        async function analyze(filterStop) {
            const text = document.getElementById('inputText').value;
            const response = await fetch('/analyze', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ text, filter_stop: filterStop })
            });
            const data = await response.json();

            if (data.error) {
                document.getElementById('errorArea').innerText = data.error;
                return;
            }

            document.getElementById('errorArea').innerText = data.errors.join(', ');
            document.getElementById('charCount').innerText = data.char_count;
            document.getElementById('wordCount').innerText = data.word_count;

            const tbody = document.querySelector('#freqTable tbody');
            tbody.innerHTML = '';
            for (const [word, count] of Object.entries(data.frequencies)) {
                tbody.innerHTML += `<tr><td>${word}</td><td>${count}</td></tr>`;
            }
        }
    </script>
</body>
</html>"
