from django.views import View
from .models import User
from django.contrib.auth import authenticate, login, logout

class UserView(View):
    """
    UserView handles the creation of new users and user authentication.
    """

    def post(self, request):
        """
        Handle POST requests to create a new user.
        """
        # Support both JSON and Form data
        import json
        try:
            if request.content_type == 'application/json':
                data = json.loads(request.body)
            else:
                data = request.POST
        except json.JSONDecodeError:
            return JsonResponse({'error': 'Invalid JSON'}, status=400)

        username = data.get('username')
        password = data.get('password')
        email = data.get('email')
        interests = data.get('interests', [])

        if not all([username, password, email]):
            return JsonResponse({'error': 'Missing required information: username, password, and email are required.'}, status=400)

        if User.objects.filter(username=username).exists():
            return JsonResponse({'error': 'Username already exists.'}, status=400)

        # Use create_user to handle password hashing correctly
        user = User.objects.create_user(
            username=username,
            password=password,
            email=email,
            interests=interests
        )
        user.save()

        return JsonResponse({
            'id': user.id,
            'username': user.username,
            'email': user.email,
            'interests': user.interests
        }, status=201)

    def get(self, request):
        """
        Handle GET requests for authentication/login.
        """
        username = request.GET.get('username')
        password = request.GET.get('password')

        if not all([username, password]):
            return JsonResponse({'error': 'Missing required information.'}, status=400)

        user = authenticate(request, username=username, password=password)

