Thought: I'll define the `Record` class, implementing `startRecording` and `stopRecording` logic using `navigator.mediaDevices.getUserMedia` and `MediaRecorder`. I'll also include a video element to preview the result.
<code>
content = "import React, { Component } from 'react';
import PropTypes from 'prop-types';

class Record extends Component {
    static propTypes = {
        record: PropTypes.bool.isRequired,
        handleRecordToggle: PropTypes.func.isRequired
    };

    constructor(props) {
        super(props);
        this.mediaRecorder = null;
        this.chunks = [];
        this.videoRef = React.createRef();
    }

    componentDidUpdate(prevProps) {
        if (this.props.record !== prevProps.record) {
            this.handleRecord();
        }
    }

    handleRecord = () => {
        if (this.props.record) {
            this.startRecording();
        } else {
            this.stopRecording();
        }
    }

    startRecording = () => {
        navigator.mediaDevices.getUserMedia({ video: true, audio: true }).then((stream) => {
            this.mediaRecorder = new MediaRecorder(stream);
            this.mediaRecorder.start();

            this.mediaRecorder.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    this.chunks.push(event.data);
                }
            };

            this.mediaRecorder.onstop = () => {
                const blob = new Blob(this.chunks, { 'type' : 'video/mp4' });
                this.chunks = [];
                const videoURL = window.URL.createObjectURL(blob);
                if (this.videoRef.current) {
                    this.videoRef.current.src = videoURL;
                }
            };
        }).catch(err => console.error("Error accessing media devices: ", err));
    }

    stopRecording = () => {
        if (this.mediaRecorder && this.mediaRecorder.state !== 'inactive') {
            this.mediaRecorder.stop();
        }
    }

    render() {
        return (
            <div className}"record-container">
                <h2>Recording</h2>
                <video ref={this.videoRef} controls autoPlay style={{ width: '320px' }} />
                <br />
                <button onClick={this.props.handleRecordToggle}>
                    {this.props.record ? 'Stop Recording' : 'Start Recording'}
                </button>
            </div>
        );
    }
}

export default Record;
