content = "from flask import Flask, request, jsonify, send_from_directory
import os

app = Flask(__name__)

# Initial Data
departments = ['Sales', 'Marketing', 'Finance']
employees = [
    {'id': 1, 'name': 'Jake', 'dept': 'Sales', 'level': 1},
    {'id': 2, 'name': 'Emily', 'dept': 'Sales', 'level': 2},
    {'id': 3, 'name': 'Amy', 'dept': 'Marketing', 'level': 2},
    {'id': 4, 'name': 'Peter', 'dept': 'Finance', 'level': 1},
    {'id': 5, 'name': 'Tom', 'dept': 'Finance', 'level': 3},
    {'id': 6, 'name': 'Susan', 'dept': 'Marketing', 'level': 1},
]

@app.route('/')
def index():
    return send_from_directory('static', 'index.html')

@app.route('/api/data', methods=['GET'])
def get_data():
    return jsonify({'departments': departments, 'employees': employees})

@app.route('/api/move', methods=['POST'])
def move_employee():
    data = request.json
    emp_id = data.get('id')
    new_dept = data.get('dept')
    new_level = data.get('level')

    emp = next((e for e in employees if e['id'] == emp_id), None)
    if not emp:
        return jsonify({'error': 'Employee not found'}), 404

    # Integrity Check: Ensure level doesn't create a gap or exceed reasonable bounds
    # For this simplified version, we just update and ensure it's a positive integer
    if new_level < 1:
        return jsonify({'error': 'Level must be at least 1'}), 400

    emp['dept'] = new_dept
    emp['level'] = new_level
    return jsonify(emp)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)
