content = "import React from \"react\";
import { GoogleMap, useLoadScript, Marker, InfoWindow } from \"@react-google-maps/api\";
import Pin from \"./Pin\";

const libraries = [\"places\"];
const mapContainerStyle = {
  width: \"100vw\",
  height: \"100vh\",
};
const center = {
  lat: 43.6532,
  lng: -79.3832,
};

const Map = ({ pins, onCreatePin, onDeletePin }) => {
  const { isLoaded, loadError } = useLoadScript({
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY || \"YOUR_API_KEY\",
    libraries,
  });

  const [selectedPin, setSelectedPin] = React.useState(null);

  if (loadError) return <div>Error loading maps</div>;
  if (!isLoaded) return <div>Loading Maps...</div>;

  return (
    <div className=\"map-container\">
      <GoogleMap
        mapContainerStyle={mapContainerStyle}
        zoom={8}
        center={center}
      >
        {pins.map((pin) => (
          <Marker
            key={pin.id}
            position={{ lat: pin.latitude, lng: pin.longitude }}
            onClick={() => setSelectedPin(pin)}
          />
        ))}

        {selectedPin && (
          <InfoWindow
            position={{ lat: selectedPin.latitude, lng: selectedPin.longitude }}
            onCloseClick={() => setSelectedPin(null)}
          >
            <div style={{ padding: '10px', maxWidth: '200px' }}>
              <h4>{selectedPin.title}</h4>
              <p>{selectedPin.description}</p>
              <Pin 
                pin={selectedPin} 
                onDeletePin={onDeletePin} 
                onCreatePin={onCreatePin} 
              />
            </div>
          </InfoWindow>
        )}
      </GoogleMap>
    </div>
  );
};

export default Map;
