  newCountry = await newCountry.save();
  res.json(newCountry);
});

app.delete('/api/countries/:id', async (req, res) => {
  const removed = await Country.findByIdAndDelete(req.params.id);
  res.json(removed);
});

// Periodic update from external API
async function updatePopulationData() {
  try {
    const response = await axios.get('https://restcountries.com/v3.1/all');
    const sorted = response.data.sort((a, b) => b.population - a.population).slice(0, 5);
    for (const c of sorted) {
      await Country.findOneAndUpdate(
        { name: c.name.common },
        { population: c.population, size: c.area, gdp: 0 }, // GDP not in this API
        { upsert: true }
      );
    }
  } catch (err) {
    console.error('Update failed:', err.message);
  }
}

setInterval(updatePopulationData, 3600000);

app.listen(3000, () => console.log('Server running on port 3000'));
