from ingest import fetch_data

class AirportAnalytics:
    def __init__(self, url):
        self.df = fetch_data(url)

    def filter_data(self, active_only=True, country=None, min_altitude=None):
        filtered = self.df.copy()
        if active_only:
            # Assuming 'Type' or 'IATA' presence indicates activity in this dataset
            filtered = filtered[filtered['IATA'].notna()]
        if country:
            filtered = filtered[filtered['Country'] == country]
        if min_altitude:
            filtered = filtered[filtered['Altitude'] >= min_altitude]
        return filtered

    def generate_chart(self, df, x_axis, y_axis, chart_type='bar', title='Airport Analysis'):
        if chart_type == 'bar':
            fig = px.bar(df, x=x_axis, y=y_axis, title=title)
        elif chart_type == 'scatter':
            fig = px.scatter(df, x=x_axis, y=y_axis, title=title)
        else:
            fig = px.histogram(df, x=x_axis, title=title)
        return fig

if __name__ == '__main__':
    app = AirportAnalytics('https://openflights.svn.sourceforge.net/svnroot/openflights/data/airports.dat')
    data = app.filter_data(country='United States')
    fig = app.generate_chart(data, x_axis='Name', y_axis='Altitude', chart_type='bar')
