Thought: I need to implement a Fibonacci calculator using matrix exponentiation to handle very large n (like 10^9) in O(log n) time. I will write the logic into a Python script. I'll include input validation for negative numbers and non-integers. Since the prompt asks for a user interface, I'll implement a loop-based CLI interface. I will save this to `fibonacci.py`.
<code>
content = "import time

def multiply(A, B):
    C = [[0, 0], [0, 0]]
    for i in range(2):
        for j in range(2):
            for k in range(2):
                C[i][j] += A[i][k] * B[k][j]
    return C

def power(A, n):
    res = [[1, 0], [0, 1]]
    while n > 0:
        if n % 2 == 1:
            res = multiply(res, A)
        A = multiply(A, A)
        n //= 2
    return res

def fibonacci(n):
    if n < 0: return None
    if n == 0: return 0
    if n == 1: return 1

    T = [[1, 1], [1, 0]]
    result_matrix = power(T, n - 1)
    return result_matrix[0][0]

def main():
    print("--- Fibonacci Matrix Exponentiation Calculator ---")
    while True:
        try:
            user_input = input("Enter an integer n (or 'q' to quit): ")
            if user_input.lower() == 'q':
                break
            n = int(user_input)
            if n < 0:
                print("Negative numbers are not supported. Please enter a non-negative integer.")
                continue

            start_time = time.time()
            result = fibonacci(n)
            end_time = time.time()

            print(f"The {n}-th Fibonacci number is: {result}")
            print(f"Calculated in {end_time - start_time:.6f} seconds.\n")
        except ValueError:
            print("This is not a valid integer. Please try again.\n")

if __name__ == '__main__':
    main()
"
